const http = require('http');
const { URL } = require('url');

function enhanceRes(res) {
  res.status = function status(code) {
    res.statusCode = code;
    return res;
  };
  res.json = function json(payload) {
    if (!res.headersSent) {
      res.setHeader('content-type', 'application/json; charset=utf-8');
    }
    res.end(JSON.stringify(payload));
  };
  return res;
}

function compilePath(path) {
  if (path === '*' || path === '/*') {
    return { regex: /^.*$/, keys: [] };
  }
  const keys = [];
  const pattern = path
    .replace(/\//g, '\\/')
    .replace(/:([^/]+)/g, (_, key) => {
      keys.push(key);
      return '([^/]+)';
    });
  return { regex: new RegExp(`^${pattern}$`), keys };
}

function createApp(isRouter = false) {
  const stack = [];

  function register(method, path, handlers) {
    const normalizedHandlers = handlers.flat();
    const compiled = compilePath(path);
    stack.push({ type: 'route', method, path, compiled, handlers: normalizedHandlers });
  }

  function use(path, ...handlers) {
    if (typeof path !== 'string') {
      handlers.unshift(path);
      path = '/';
    }
    handlers.flat().forEach((handler) => {
      stack.push({ type: 'middleware', path, handler });
    });
  }

  async function handle(req, res, out) {
    enhanceRes(res);
    const originalUrl = req.originalUrl || req.url;
    const pathname = (req.path || new URL(req.url, 'http://localhost').pathname);
    req.originalUrl = originalUrl;
    req.path = pathname;
    req.params = req.params || {};

    let index = 0;

    const next = async (err) => {
      const layer = stack[index++];
      if (!layer) {
        if (out) {
          return out(err);
        }
        if (err) {
          res.statusCode = err.status || 500;
          return res.json({ error: err.message || 'Internal Server Error', code: err.code || 'INTERNAL_ERROR' });
        }
        res.statusCode = 404;
        return res.json({ error: `Route not found: ${req.method} ${req.originalUrl}` });
      }

      try {
        if (layer.type === 'middleware') {
          const isErrorHandler = layer.handler.length === 4;
          const matchesPrefix = layer.path === '/' || req.path === layer.path || req.path.startsWith(layer.path.endsWith('/') ? layer.path : `${layer.path}/`);
          if (!matchesPrefix) {
            return next(err);
          }

          if (typeof layer.handler.handle === 'function') {
            const originalReqUrl = req.url;
            const originalPath = req.path;
            if (layer.path !== '/' && req.path.startsWith(layer.path)) {
              req.url = req.url.slice(layer.path.length) || '/';
              req.path = req.path.slice(layer.path.length) || '/';
            }
            return layer.handler.handle(req, res, async (routerErr) => {
              req.url = originalReqUrl;
              req.path = originalPath;
              return next(routerErr || err);
            });
          }

          if (err) {
            if (isErrorHandler) {
              return layer.handler(err, req, res, next);
            }
            return next(err);
          }

          if (isErrorHandler) {
            return next();
          }

          return layer.handler(req, res, next);
        }

        if (err) {
          return next(err);
        }

        if (layer.method !== req.method) {
          return next();
        }

        const match = layer.compiled.regex.exec(req.path);
        if (!match) {
          return next();
        }

        req.params = {};
        layer.compiled.keys.forEach((key, i) => {
          req.params[key] = decodeURIComponent(match[i + 1]);
        });

        let routeIndex = 0;
        const runRoute = async (routeErr) => {
          if (routeErr) {
            return next(routeErr);
          }
          const handler = layer.handlers[routeIndex++];
          if (!handler) {
            return;
          }
          return handler(req, res, runRoute);
        };

        return runRoute();
      } catch (caught) {
        return next(caught);
      }
    };

    return next();
  }

  const app = {
    use,
    get: (path, ...handlers) => register('GET', path, handlers),
    post: (path, ...handlers) => register('POST', path, handlers),
    handle,
    listen(port, callback) {
      const server = http.createServer((req, res) => {
        handle(req, res);
      });
      return server.listen(port, callback);
    }
  };

  if (isRouter) {
    return app;
  }

  return app;
}

function json() {
  return async (req, _res, next) => {
    const methodsWithBody = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);
    if (!methodsWithBody.has(req.method)) {
      req.body = req.body || {};
      return next();
    }

    let raw = '';
    req.on('data', (chunk) => {
      raw += chunk;
    });
    req.on('end', () => {
      if (!raw) {
        req.body = {};
        return next();
      }
      try {
        req.body = JSON.parse(raw);
        return next();
      } catch (error) {
        error.status = 400;
        error.code = 'INVALID_JSON';
        return next(error);
      }
    });
    req.on('error', next);
  };
}

function Router() {
  return createApp(true);
}

function express() {
  return createApp(false);
}

express.Router = Router;
express.json = json;

module.exports = express;
